var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"보름 뒤","JPN":"2週間後","ENG":"15 days later","TWN":"半個月後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"말씀하신 곳에 거의 도착했습니다만.","JPN":"目的地まであともう少しですが。","ENG":"We've almost arrived at the destination you requested.","TWN":"就快抵達你說的目的地了。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"대낮부터 이런 곳에서 데이트라니 취향이 참 독특하시네요.","JPN":"真っ昼間からこのような場所でデートだなんて、独特ですね。","ENG":"Having a date in a place like this in broad daylight? That's some questionable taste you got there.","TWN":"大白天的在這種地方約會，你的喜好很特別呢。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하, 하하. 그게…… 데이트는 아닌데요.","JPN":"は、はは。それが……デートはないのよ。","ENG":"Hah... Hah hah. Well... It's not a date.","TWN":"哈哈……這不是約會啦。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"죄송해요. 사장님. 괜한 오해를 불러일으켜서.","JPN":"申し訳ありません、社長。変な誤解を招いてしまいまして。","ENG":"I'm sorry for causing a misunderstanding, Boss.","TWN":"老闆抱歉，引起不必要的誤會。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 괜찮다네.","JPN":"私は大丈夫だ。","ENG":"It's all right with me.","TWN":"我是無所謂。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 이곳에서 소개해 줄 사람이 있다는 말은…….","JPN":"それより、ここで私に紹介したいという者は……","ENG":"Anyway, who is this person you wanted to introduce me to...?","TWN":"倒是你說要介紹一個人給我認識……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"안녕하세요, 브라운 씨.","JPN":"こんにちは、ブラウンさん。","ENG":"Hello, Mr. Brown.","TWN":"你好，布朗先生！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"오늘도 친구분을 보러 오셨군요, 말레나 스키너.","JPN":"今日もお友達に会いに来たんですね、マレーナ・スキナー。","ENG":"I see you came to see your friend again, Malena Skinner.","TWN":"今天又來看朋友了啊，瑪蓮娜·史金納。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 매일 찾아오는 동료가 있다니, 그분도 쓸쓸하지는 않을 겁니다.","JPN":"こうやって毎日訪ねる仲間がいたら、あの方も寂しい思いはしないでしょうね。","ENG":"Having a colleague who visits every day. I'm sure he won't be lonely.","TWN":"每天都有像你這樣的同伴來探望，那位朋友也不會感到孤單了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"그런데 옆에 계신 신사분은……?","JPN":"ところで、隣の方は……？","ENG":"But who is the gentleman next to you...?","TWN":"不過，旁邊的這位先生是……？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 저희 사장님이세요.","JPN":"あ、うちの社長です。","ENG":"Oh, this is my boss.","TWN":"啊，這是我們的老闆。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"카나리아 스쿼드, 그 소문의 코치시로군요. 당사자를 직접 보게 될 줄은 몰랐네요.","JPN":"カナリア・スクワッド、あのウワサのコーチですね。直接ご本人にお会いできるとは。","ENG":"So, you are the rumored coach of the Canary Squad. I never imagined that I'd see you in person.","TWN":"原來金絲雀小隊傳聞中的教練是你啊。沒想到能親眼見到本人。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"내노라 하는 샤레이드의 강팀들을 차례로 쓰러트리고 있다죠?","JPN":"数あるシャレードの強豪を次々と倒しているらしいではないですか。","ENG":"I heard you defeated all the powerful teams in Charade.","TWN":"聽說你們把那些查雷德強隊一個個地都擊敗了？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 고맙네. 응원이라면 감사히 받지.","JPN":"はは、嬉しいな。応援ならありがたく受け取ろう。","ENG":"Haha, I'm flattered. Thank you for cheering us on.","TWN":"哈哈，謝謝你。你的支持我欣然接受。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Um...","TWN":"呃……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"아하, 이거 아무래도 시간을 빼앗은 모양이군요.","JPN":"ああ、すみません。つい待たせてしまいましたね。","ENG":"A-ha, it seems I have taken too much of your time.","TWN":"啊哈，看起來是佔用了你們的時間啊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"여기 묘역 방문 허가증입니다. 요즘 치안이 영 좋지 않아서 말이죠.","JPN":"どうぞ、お墓の訪問許可証です。最近治安がよくなくて。","ENG":"Here is your cemetery visitor's pass. It's because the security around here recently hasn't been so good.","TWN":"拿著，這是墓園訪問許可證。最近治安不太好。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"감사합니다. 브라운 씨.","JPN":"ありがとうございます、ブラウンさん。","ENG":"Thank you, Mr. Brown.","TWN":"非常感謝，布朗先生。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼…….","JPN":"それでは……","ENG":"Then...","TWN":"那我們就……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 저도 슬슬 다음을 준비할 때로군요.","JPN":"では、私もそろそろ次の準備に移らないと。","ENG":"Then, I think it's time I prepared for the next one.","TWN":"那麼，我也該準備下一步了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"멀지 않은 날, 다시 만나게 될 겁니다. 관리자.","JPN":"また遠からず、お会いできるはずですよ、管理者。","ENG":"We will meet again soon, Administrator.","TWN":"不久的將來，我們會再見面的，管理者。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 도시관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>シャレード都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Charade City Management.</color>","TWN":"<color=#ffd34c>查雷德城市管理局的通知。</color>"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 일부 지역에 침식파 밀도가 급격히 상승하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、都市中心部の一部の地域において侵食波密度が急激に上昇しています。</color>","ENG":"<color=#ffd34c>Currently, Corruption ray levels are rapidly rising in some areas of the city.</color>","TWN":"<color=#ffd34c>目前市中心部分區域的侵蝕波密度急速增加。</color>"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 추세로 볼 때, 곧 급성 침식 경보가 발령될 예정입니다..</color>","JPN":"<color=#ffd34c>現在の状況から、まもなく急性侵食警報が発令される見込みです。</color>","ENG":"<color=#ffd34c>Given the current trend, an acute Corruption alert may be issued soon.</color>","TWN":"<color=#ffd34c>照目前的情勢看來，很快就會發布緊急侵蝕警報<。/color>"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"제길, 샤레이드 한 가운데서 침식 현상이라니!","JPN":"くそっ、シャレードのど真ん中で侵食現象が起きるなんて！","ENG":"Dammit! A Counterside Effect in the middle of Charade?!","TWN":"該死，在查雷德的市中心竟然出現了侵蝕現象！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"서둘러! 시민들의 안전이 최우선이다!","JPN":"急げ！　市民の安全が第一だ！","ENG":"Hurry! The safety of the citizens is our top priority!","TWN":"快點！市民的安全是最重要的！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"구역에서 산발적으로 CSE 레벨 급속 상승 중! 3종 출몰이 확인된 곳도 있습니다!","JPN":"区域で散発的にCSEレベルが急速に上昇中！　第3種の出現が確認されたところもあります！","ENG":"CSE levels are rising sporadically and rapidly in the area! A Category 3 has also been sighted!","TWN":"區域內CSE等級正在迅速上升！發現3類侵蝕體出沒的跡象！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"겨우 이정도 병력으로 모든 구역을 커버할 수는 없어!","JPN":"たかがこの程度の兵力で、すべての区域をカバーできない！","ENG":"We can't cover all areas with this many troops!","TWN":"僅憑這點兵力，無法覆蓋所有區域！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"오지만디아스님께 연락은 해봤나?","JPN":"オジマンディアス様には連絡してみたか？","ENG":"Have you contacted Ozymandias yet?","TWN":"有聯繫過奧茲曼迪亞斯了嗎！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그게 연락은 해봤는데 말입니다. 아마도…….","JPN":"それが、連絡はしてみましたが、おそらく……","ENG":"Well, I tried, but...","TWN":"那個，我試著聯繫了，但……可能……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"쳇, 그럼 그렇지! 우선, 담당 구역 태스크포스에게 연락부터 돌린 뒤에…….","JPN":"チッ、だと思った！　まずは、担当区域のタスクフォースに連絡して……","ENG":"Tch, I knew it! First, call the TASKFORCE that's in charge of protecting that area, and–","TWN":"呃！果然如此！先聯繫負責有關區域的特遣勢力……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"아니, 그럴 필요 없거든~","JPN":"いいえ、その必要はないわ～","ENG":"No, that won't be necessary.","TWN":"不，那個大可不必～"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"엇?","JPN":"あれっ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야? 뭘 그렇게 얼 타고 있어? 너네 나 처음 봐?","JPN":"何をそんなにボーっとしてるわけ？　あなたたち、私に会うのは初めてかしら？","ENG":"Huh? What are you staring at? It's not the first time you've seen me, is it?","TWN":"怎麼了？你們怎麼這麼緊張？是第一次見到我嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"오지만디아스님……?","JPN":"オジマンディアス様……？","ENG":"Miss Ozymandias...?","TWN":"奧茲曼迪亞斯……?"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이거 실망이네~","JPN":"残念だわ～","ENG":"This is disappointing!","TWN":"真是失望啊~"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"또 술이나 진탕 마시고 호출 씹었다고 생각한 거야?","JPN":"またお酒飲んじゃって、呼び出しを無視したとでも思った？","ENG":"Did you think that I'd ignore the call after another night of drinking?","TWN":"又以為我喝得爛醉如泥，連電話都不接了？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"아, 아니요……. 그게 아니라…….","JPN":"い、いいえ……そうじゃなくて……","ENG":"N-no... That's not it...","TWN":"不……不是那樣的……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이래 봬도 샤레이드 공인 S급 카운터라고.","JPN":"こう見えてもシャレード公認のS級カウンターなのよ。","ENG":"I am still Charade's official Grade S Counter.","TWN":"我可是查雷德公認的S級制裁者。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이 도시에서 가장 명예로운 자로서, 지켜야 할 의무를 외면할 리가 없잖아?","JPN":"この都市でもっとも名誉ある者として、守るべき義務から目を背けるわけないでしょ？","ENG":"As the most honorable person of this city, I wouldn't turn a blind eye to my duties, right?","TWN":"作為這座城市裡享有最高榮譽的人，怎麼可能會忽視我應盡的義務呢？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그, 그렇습니다!","JPN":"お、おっしゃるとおりです！","ENG":"Y-yes, ma'am!","TWN":"是、是的！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"읏차! 그로니아 사태 이후로 대침식전은 오랜만인가?","JPN":"よいしょっと！　グロニア事態以来、対侵食戦は久しぶりかしら？","ENG":"Hup! It's been a long time since the last anti-Corruption warfare during the Gronia incident, right?","TWN":"哎呀！自從格羅尼亞事件後，好久沒有反侵蝕戰了吧？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"결승도 얼마 안 남았으니까, 미리 몸을 풀어두는 것도 나쁘지는 않겠지?","JPN":"もうすぐ決勝だし、あらかじめウォーミングアップしておくのも悪くないわ。","ENG":"With the finals just around the corner, it won't be a bad idea to warm up in advance, right?","TWN":"決賽也快到了，提前活動一下筋骨也不錯喔？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 그럼, 내가 활약할 스테이지가 어디야?","JPN":"ところで、私が活躍するステージはどこ？","ENG":"Now, then. Where's the stage I'll be starring in?","TWN":"那麼，我要大顯身手的舞台在哪裡？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이 앞입니다. 오지만디아스님.","JPN":"ここの前です、オジマンディアス様。","ENG":"Right in front of you, Miss Ozymandias.","TWN":"就在前面，奧茲曼迪亞斯。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"관측소에서 지원 요청이 왔었습니다. 현장에 3종이 출몰한 것 같습니다.","JPN":"観測所から支援要請が来ました。現場に第3種が出現したようです。","ENG":"A request came from the observatory. A Category 3 seems to have appeared on the scene.","TWN":"觀測站發來了支援請求。現場似乎出現了3類的敵人。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 3종 정도면 가뿐하겠지.","JPN":"まあ、第3種なら楽勝ね。","ENG":"Eh, a Category 3 is a cinch.","TWN":"唔，3類的話應該很輕鬆吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"금방 끝내고 올 테니까. 여기서 잔챙이라도 처리하고 있어.","JPN":"すぐ終わらせて来るから、ここで雑魚の相手でもしていなさい。","ENG":"I'll be back in no time. You take care of the grunts here.","TWN":"我很快就會回來。你們留在這裡清理一下小嘍囉。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어차피 내 사슬검 반경 안에 있어봤자, 방해만 되거든.","JPN":"どうせ私の蛇腹剣の範囲内にいられたって邪魔なだけだし。","ENG":"You'll be in my way by being within range of my whip sword, anyway.","TWN":"反正在我的鏈刃範圍內，你們只會礙事。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"Y-yes, ma'am!","TWN":"知、知道了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"……이상하다?","JPN":"……おかしいな。","ENG":"...That's odd.","TWN":"……呃，有點奇怪啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"저 인간이 웬일이지? 평소라면 다 끝날 때쯤 와서 보고서에 이름만 올릴 텐데?","JPN":"あの人、どうした？　いつもなら全部片付くころに来て、報告書に名前だけ書くだけなのに。","ENG":"What's gotten into her? She would normally come when everything is finished and just put her name on the report.","TWN":"那女人平時都是等一切結束後才出現，在報告上簽個名就走了啊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"왠지 저는 알 것 같습니다, 선배님.","JPN":"なんだかわかる気がします、先輩。","ENG":"I think I know why, sir.","TWN":"我好像知道為什麼了，長官。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"저번 경기 못 보셨습니까? 마지막에 오지만디아스님이 깜짝 출현하셨지 말입니다.","JPN":"この前の試合、見ましたか？　最後にオジマンディアス様がサプライズ登場したんですよ。","ENG":"Didn't you see the recent match? Miss Ozymandias made a surprise appearance at the last minute.","TWN":"上次比賽你看了吧？最後奧茲曼迪亞斯突然出現了呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그때 챔피언이 휘두른 사슬검을 받아 친 소녀가 있었는데…….","JPN":"あの時、チャンピオンが振り回した蛇腹剣を打ち返した少女がいまして……","ENG":"There was a girl who reflected the champion's whip sword...","TWN":"當時有個少女接住了冠軍揮舞的鏈劍……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"아무래도 그것 때문에 자극받으신 거 아니겠습니까?","JPN":"どうやらそれで刺激されたんじゃないですか？","ENG":"and I think that provoked her.","TWN":"恐怕是因為那件事刺激到她了吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……쉽군.","JPN":"……首尾よく入れましたね。","ENG":"...Easy.","TWN":"……簡單。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"역시 공인 S급 카운터의 신분은 편리하네.","JPN":"やはり公認S級カウンターの身分は便利です。","ENG":"The identity of an official Grade S Counter sure is convenient.","TWN":"果然，作為公認S級制裁者的身份還是很方便的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"침식현상이 발생하면, 도시 수호를 명분으로 어디든 출입할 수 있으니까.","JPN":"侵食現象が発生したら、都市の守護を言い訳にどこにでも出入りできるから。","ENG":"I'm able to go anywhere under the pretext of protecting the city whenever a Counterside Effect occurs.","TWN":"一旦發生侵蝕現象，就可以以守護城市為名，隨意出入。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"이걸로 다섯 번째.","JPN":"これで五つ目。","ENG":"This will be the fifth one.","TWN":"這是第五個了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"이제 마지막 남은 대균열은 로터스뿐인가.","JPN":"もう最後の大亀裂はロータスですか。","ENG":"Now, the only remaining Grand Dimension Crevice will be in Lotus.","TWN":"現在只剩下洛德斯的大峽谷了嗎。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"샤레이드와 작별을 고하기 전에.","JPN":"シャレードとお別れする前に、","ENG":"Before I say goodbye to Charade.","TWN":"在和查雷德告別之前。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"끝맺음 정도는 확실히 지어두는 편이 좋겠지.","JPN":"きちんとケジメをつけておいた方がいいですね。","ENG":"I must take care of all loose ends.","TWN":"還是把事情徹底解決掉比較好。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};